class Solution:
    def monotoneIncreasingDigits(self, n):
        s = str(n)
        L = len(s)
        def mono(t):
            return all(t[i] <= t[i + 1] for i in range(len(t) - 1))
        if mono(s):
            return n
        best = 0
        for i in range(L):
            d = int(s[i])
            for nd in range(d - 1, -1, -1):
                cand = s[:i] + str(nd) + '9' * (L - i - 1)
                cv = int(cand)
                if cv <= n and mono(cand):
                    if cv > best:
                        best = cv
        return best

