class Solution:
    def monotoneIncreasingDigits(self, n):
        d = list(str(n))
        m = len(d)
        mark = m
        for i in range(m - 1, 0, -1):
            if d[i - 1] > d[i]:
                d[i - 1] = str(int(d[i - 1]) - 1)
                mark = i
        for i in range(mark, m):
            d[i] = '9'
        return int(''.join(d))

