var monotoneIncreasingDigits = function(n) {
    const d = String(n).split('');
    const m = d.length;
    let mark = m;
    for (let i = m - 1; i > 0; i--) {
        if (d[i - 1] > d[i]) {
            d[i - 1] = String(Number(d[i - 1]) - 1);
            mark = i;
        }
    }
    for (let i = mark; i < m; i++) d[i] = '9';
    return Number(d.join(''));
};
